t.t:
.hero-section {
    background: linear-gradient(135deg, var(--p-primary) 0%, #185FA5 100%);
    border-radius: 14px;
    padding: 52px 48px;
    color: #fff;
    margin-bottom: 40px;
    position: relative;
    overflow: hidden;
}
.hero-section::after {
    content: '';
    position: absolute;
    right: -60px; top: -60px;
    width: 280px; height: 280px;
    border-radius: 50%;
    background: rgba(255,255,255,0.05);
}
.hero-section h1 {
    font-size: 30px;
    font-weight: 700;
    margin-bottom: 12px;
    line-height: 1.3;
    position: relative;
}
.hero-section p {
    font-size: 16px;
    color: rgba(255,255,255,0.78);
    max-width: 520px;
    margin-bottom: 28px;
}
.hero-actions { display: flex; gap: 12px; flex-wrap: wrap; }
.cards-row {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
    margin-bottom: 40px;
}
@media(max-width:700px) { .cards-row { grid-template-columns: 1fr; } }
.info-card {
    background: var(--p-card);
    border: 1px solid var(--p-border);
    border-radius: 12px;
    padding: 24px 22px;
}
.info-card .ic-icon { font-size: 28px; margin-bottom: 12px; }
.info-card h3 { font-size: 16px; font-weight: 600; color: var(--p-text); margin-bottom: 6px; }
.info-card p  { font-size: 13.5px; color: var(--p-muted); line-height: 1.55; margin-bottom: 14px; }
.section-title {
    font-size: 20px;
    font-weight: 700;
    color: var(--p-text);
    margin-bottom: 16px;
}
.opp-preview-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 16px;
    margin-bottom: 24px;
}
.opp-mini-card {
    background: var(--p-card);
    border: 1px solid var(--p-border);
    border-radius: 10px;
    padding: 18px;
    display: flex;
    flex-direction: column;
    gap: 8px;
    transition: box-shadow .2s, transform .2s;
}
.opp-mini-card:hover { box-shadow: 0 4px 16px rgba(15,76,129,0.10); transform: translateY(-2px); }
.opp-mini-title { font-size: 14px; font-weight: 600; color: var(--p-text); line-height: 1.4; }
.opp-mini-company { font-size: 12px; color: var(--p-muted); }
.opp-mini-footer { display: flex; justify-content: space-between; align-items: center; padding-top: 8px; border-top: 1px solid var(--p-border); margin-top: 4px; }
.opp-mini-prazo { font-size: 11.5px; color: var(--p-muted); }
.view-all { text-align: center; margin-top: 8px; }

.page-header { margin-bottom: 28px; }
.page-header h1 { font-size: 26px; font-weight: 700; color: var(--p-text); margin-bottom: 6px; }
.page-header p  { font-size: 14px; color: var(--p-muted); }
.filter-bar {
    background: var(--p-card);
    border: 1px solid var(--p-border);
    border-radius: 10px;
    padding: 14px 18px;
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 24px;
    flex-wrap: wrap;
}
.search-wrap { position: relative; flex: 1; min-width: 200px; }
.search-wrap input {
    width: 100%;
    padding: 8px 12px 8px 36px;
    border: 1px solid var(--p-border);
    border-radius: 6px;
    font-size: 13.5px;
    font-family: inherit;
    outline: none;
    transition: border .15s;
}
.search-wrap input:focus { border-color: var(--p-primary); }
.search-icon { position: absolute; left: 11px; top: 50%; transform: translateY(-50%); color: var(--p-muted); }
.filter-pills { display: flex; gap: 6px; flex-wrap: wrap; }
.fpill {
    padding: 5px 14px;
    border-radius: 20px;
    font-size: 12.5px;
    border: 1px solid var(--p-border);
    background: #fff;
    color: var(--p-muted);
    cursor: pointer;
    transition: all .15s;
    font-family: inherit;
}
.fpill:hover, .fpill.active { background: var(--p-primary); color: #fff; border-color: var(--p-primary); }
.opp-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 20px;
}
.opp-card {
    background: var(--p-card);
    border: 1px solid var(--p-border);
    border-radius: 12px;
    padding: 22px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    transition: box-shadow .2s, transform .2s;
}
.opp-card:hover { box-shadow: 0 6px 20px rgba(15,76,129,0.11); transform: translateY(-3px); }
.opp-card-top { display: flex; justify-content: space-between; align-items: flex-start; }
.company-row { display: flex; align-items: center; gap: 8px; }
.company-initials {
    width: 32px; height: 32px;
    border-radius: 50%;
    background: var(--p-primary-light);
    color: var(--p-primary);
    font-size: 11px; font-weight: 700;
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;
}
.company-name { font-size: 12.5px; color: var(--p-muted); }
.opp-title { font-size: 15px; font-weight: 600; color: var(--p-text); line-height: 1.4; }
.opp-desc  { font-size: 13px; color: var(--p-muted); line-height: 1.55;
    display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }
.opp-meta  { display: flex; gap: 12px; flex-wrap: wrap; }
.opp-meta-item { font-size: 12px; color: var(--p-muted); display: flex; align-items: center; gap: 4px; }
.opp-meta-item strong { color: var(--p-text); }
.opp-footer {
    display: flex; justify-content: space-between; align-items: center;
    padding-top: 12px; border-top: 1px solid var(--p-border); margin-top: auto;
}
.prazo-label { font-size: 12px; color: var(--p-muted); }
.prazo-label strong { color: var(--p-text); }
.empty-state { text-align: center; padding: 64px 20px; color: var(--p-muted); grid-column: 1/-1; }
.empty-state .es-icon { font-size: 40px; margin-bottom: 12px; }
.empty-state p { font-size: 15px; margin-bottom: 16px; }

t.script:
let activeFilter = 'todos';
function setFilter(el, tipo) {
    document.querySelectorAll('.fpill').forEach(p => p.classList.remove('active'));
    el.classList.add('active');
    activeFilter = tipo;
    filterCards();
}
function filterCards() {
    const q = document.getElementById('opp-search').value.toLowerCase();
    document.querySelectorAll('.opp-card').forEach(card => {
        const matchTipo = activeFilter === 'todos' || card.dataset.tipo === activeFilter;
        const matchQ = !q || card.dataset.search.toLowerCase().includes(q);
        card.style.display = (matchTipo && matchQ) ? '' : 'none';
    });
}
